import { useEffect, useRef } from 'react'
import type { Contact, Template } from '../../types'
import { drawVerticalBlock } from '../../lib/verticalText'

/** 1mm あたりのピクセル数 (96 dpi 基準) */
const MM_TO_PX = 96 / 25.4 // ≈ 3.78

/**
 * デフォルトテンプレート: A4 12面ラベル (86.4×42.3mm) 縦書き
 * テンプレート選択 UI が実装されるまでのフォールバック用。
 */
export const DEFAULT_TEMPLATE: Template = {
  id: 'default-a4-12',
  name: '標準 (A4 12面)',
  orientation: 'vertical',
  labelWidth: 86.4,
  labelHeight: 42.3,
  postalCode: {
    x: 36,        // 〒マーク左端 (mm)
    y: 4.5,       // 上端からの距離 (mm)
    digitSpacing: 5.5,
    fontSize: 10,
  },
  recipient: {
    nameX: 79,    // 氏名カラム右端 (mm)
    nameY: 8,     // 上端からの距離 (mm)
    nameFont: 13,
    addressX: 69, // 住所ブロック右端 (mm)
    addressY: 8,  // 上端からの距離 (mm)
    addressFont: 8.5,
  },
  sender: {
    nameX: 16,    // 差出人氏名カラム右端 (mm)
    nameY: 24,
    nameFont: 6.5,
    addressX: 8,  // 差出人住所ブロック右端 (mm)
    addressY: 24,
    addressFont: 5.5,
  },
}

/**
 * デフォルトテンプレート: A4 12面ラベル (86.4×42.3mm) 横書き
 */
export const DEFAULT_TEMPLATE_HORIZONTAL: Template = {
  id: 'default-a4-12-h',
  name: '標準 (A4 12面) 横書き',
  orientation: 'horizontal',
  labelWidth: 86.4,
  labelHeight: 42.3,
  postalCode: {
    x: 5,
    y: 3,
    digitSpacing: 7,
    fontSize: 9,
  },
  recipient: {
    nameX: 5,
    nameY: 13,
    nameFont: 12,
    addressX: 5,
    addressY: 24,
    addressFont: 8.5,
  },
  sender: {
    nameX: 50,
    nameY: 33,
    nameFont: 6.5,
    addressX: 50,
    addressY: 37,
    addressFont: 5.5,
  },
}

/** 郵便番号を "NNN-NNNN" 形式に整形する */
function formatPostalCode(raw: string): string {
  const digits = raw.replace(/\D/g, '')
  if (digits.length === 7) return `${digits.slice(0, 3)}-${digits.slice(3)}`
  return raw
}

/** px 変換ヘルパー */
function mm(value: number, scale: number): number {
  return value * MM_TO_PX * scale
}

interface LabelCanvasProps {
  contact: Contact
  template?: Template
  /** 表示倍率 (デフォルト 1.0) */
  zoom?: number
}

export default function LabelCanvas({
  contact,
  template = DEFAULT_TEMPLATE,
  zoom = 1,
}: LabelCanvasProps) {
  const canvasRef = useRef<HTMLCanvasElement>(null)

  const canvasW = Math.round(mm(template.labelWidth, zoom))
  const canvasH = Math.round(mm(template.labelHeight, zoom))

  useEffect(() => {
    const canvas = canvasRef.current
    if (!canvas) return
    const ctx = canvas.getContext('2d')
    if (!ctx) return

    // デバイスピクセル比を考慮した高解像度レンダリング
    const dpr = window.devicePixelRatio || 1
    canvas.width = canvasW * dpr
    canvas.height = canvasH * dpr
    canvas.style.width = `${canvasW}px`
    canvas.style.height = `${canvasH}px`
    ctx.scale(dpr, dpr)

    renderLabel(ctx, contact, template, zoom)
  }, [contact, template, zoom, canvasW, canvasH])

  return (
    <canvas
      ref={canvasRef}
      style={{ width: canvasW, height: canvasH }}
      className="shadow-sm"
    />
  )
}

function renderLabel(
  ctx: CanvasRenderingContext2D,
  contact: Contact,
  tpl: Template,
  zoom: number,
): void {
  const s = zoom // スケール係数 (zoom のみ。MM_TO_PX は mm() 内で適用済み)
  const W = mm(tpl.labelWidth, s)
  const H = mm(tpl.labelHeight, s)

  // ─── 背景 ───────────────────────────────────────────────
  ctx.fillStyle = '#ffffff'
  ctx.fillRect(0, 0, W, H)

  // ─── 外枠 ───────────────────────────────────────────────
  ctx.strokeStyle = '#d1d5db'
  ctx.lineWidth = 0.5
  ctx.strokeRect(0.5, 0.5, W - 1, H - 1)

  // ─── 郵便番号 ────────────────────────────────────────────
  if (tpl.postalCode && contact.postalCode) {
    const pc = tpl.postalCode
    const fontSize = mm(pc.fontSize / 2.835, s) // pt → mm → px (1pt≈0.353mm)
    const spacing = mm(pc.digitSpacing, s)
    const startX = mm(pc.x, s)
    const baseY = mm(pc.y, s)

    ctx.fillStyle = '#111827'
    ctx.font = `${fontSize}px "Hiragino Kaku Gothic ProN", "Meiryo", sans-serif`
    ctx.textAlign = 'left'
    ctx.textBaseline = 'top'

    // 〒マーク
    ctx.fillText('〒', startX - spacing * 0.3, baseY)

    const digits = contact.postalCode.replace(/\D/g, '')
    const formatted = formatPostalCode(digits)
    // ハイフン込みで1文字ずつ等間隔に描画
    let ox = startX + spacing * 0.5
    for (const ch of formatted) {
      ctx.fillText(ch, ox, baseY)
      ox += ch === '-' ? spacing * 0.5 : spacing
    }
  }

  if (tpl.orientation === 'horizontal') {
    renderHorizontalLabel(ctx, contact, tpl, s)
  } else {
    renderVerticalLabel(ctx, contact, tpl, s)
  }
}

/** 縦書きラベルの宛先・差出人描画 */
function renderVerticalLabel(
  ctx: CanvasRenderingContext2D,
  contact: Contact,
  tpl: Template,
  s: number,
): void {
  // ─── 宛先 氏名 ───────────────────────────────────────────
  {
    const rc = tpl.recipient
    const nameFontPx = mm(rc.nameFont / 2.835, s)
    const name = `${contact.familyName}${contact.givenName}`
    const honorific = contact.honorific || '様'

    ctx.fillStyle = '#111827'
    ctx.font = `${nameFontPx}px "Hiragino Mincho ProN", "Yu Mincho", "MS PMincho", serif`

    // 氏名: 右端カラム、敬称は独立した右隣カラム
    drawVerticalBlock({
      ctx,
      lines: [honorific, name],
      rightX: mm(rc.nameX, s),
      topY: mm(rc.nameY, s),
      fontSize: nameFontPx,
      convertNumbers: false,
    })
  }

  // ─── 宛先 住所 ───────────────────────────────────────────
  {
    const rc = tpl.recipient
    const addrFontPx = mm(rc.addressFont / 2.835, s)

    // 住所を2列に分割: 都道府県+市区町村 / 番地+建物名
    const addrLine1 = `${contact.prefecture}${contact.city}`
    const addrLine2 = `${contact.street}${contact.building ? `　${contact.building}` : ''}`

    ctx.fillStyle = '#111827'
    ctx.font = `${addrFontPx}px "Hiragino Mincho ProN", "Yu Mincho", "MS PMincho", serif`

    drawVerticalBlock({
      ctx,
      lines: [addrLine1, addrLine2].filter(Boolean),
      rightX: mm(rc.addressX, s),
      topY: mm(rc.addressY, s),
      fontSize: addrFontPx,
      convertNumbers: true,
    })
  }
}

/** 横書きラベルの宛先・差出人描画 */
function renderHorizontalLabel(
  ctx: CanvasRenderingContext2D,
  contact: Contact,
  tpl: Template,
  s: number,
): void {
  const serifFont = '"Hiragino Mincho ProN", "Yu Mincho", "MS PMincho", serif'

  // ─── 宛先 氏名 ───────────────────────────────────────────
  {
    const rc = tpl.recipient
    const nameFontPx = mm(rc.nameFont / 2.835, s)
    const honorific = contact.honorific || '様'
    const fullName = `${contact.familyName}${contact.givenName}　${honorific}`

    ctx.fillStyle = '#111827'
    ctx.font = `${nameFontPx}px ${serifFont}`
    ctx.textAlign = 'left'
    ctx.textBaseline = 'top'
    ctx.fillText(fullName, mm(rc.nameX, s), mm(rc.nameY, s))
  }

  // ─── 宛先 住所 ───────────────────────────────────────────
  {
    const rc = tpl.recipient
    const addrFontPx = mm(rc.addressFont / 2.835, s)
    const lineH = addrFontPx * 1.5

    const addrLines = [
      `${contact.prefecture}${contact.city}`,
      `${contact.street}${contact.building ? `　${contact.building}` : ''}`,
    ].filter(Boolean)

    ctx.fillStyle = '#111827'
    ctx.font = `${addrFontPx}px ${serifFont}`
    ctx.textAlign = 'left'
    ctx.textBaseline = 'top'

    addrLines.forEach((line, i) => {
      ctx.fillText(line, mm(rc.addressX, s), mm(rc.addressY, s) + i * lineH)
    })
  }

  // ─── 差出人エリアは将来 Sender エンティティで置き換える ──────
  // 仕様: 差出人は別エンティティなので、ここでは表示領域の余白のみ確保
}

import { useEffect, useRef, useState } from 'react'
import { useShallow } from 'zustand/shallow'
import { useContactStore } from '../../stores/contactStore'
import { usePreviewStore } from '../../stores/previewStore'
import { useDecorationStore } from '../../stores/decorationStore'
import LabelCanvas, { DEFAULT_TEMPLATE, DEFAULT_TEMPLATE_HORIZONTAL } from './LabelCanvas'
import LabelEditorOverlay from './LabelEditorOverlay'
import WatermarkLayer from './WatermarkLayer'
import QROverlay from './QROverlay'
import { useLabelStore } from '../../stores/labelStore'
import type { Contact, Template, Watermark, QRConfig } from '../../types'

/** 1mm あたりのピクセル数 (96 dpi 基準) — LabelCanvas と同じ定数 */
const MM_TO_PX = 96 / 25.4

const ZOOM_MIN = 0.5
const ZOOM_MAX = 4.0
const ZOOM_STEP = 0.25

export default function PreviewArea() {
  const { contacts, selectedIds } = useContactStore(
    useShallow((s) => ({ contacts: s.contacts, selectedIds: s.selectedIds })),
  )
  const {
    zoom,
    selectedTemplate,
    previewContactIndex,
    setZoom,
    setPreviewContactIndex,
    setSelectedTemplate,
  } = usePreviewStore(
    useShallow((s) => ({
      zoom: s.zoom,
      selectedTemplate: s.selectedTemplate,
      previewContactIndex: s.previewContactIndex,
      setZoom: s.setZoom,
      setPreviewContactIndex: s.setPreviewContactIndex,
      setSelectedTemplate: s.setSelectedTemplate,
    })),
  )
  const { watermark, qrConfig } = useDecorationStore(
    useShallow((s) => ({ watermark: s.watermark, qrConfig: s.qrConfig })),
  )
  const { orientation, layout, setLayout, resetOffset } = useLabelStore(
    useShallow((s) => ({
      orientation: s.orientation,
      layout: s.layout,
      setLayout: s.setLayout,
      resetOffset: s.resetOffset,
    })),
  )

  const selectedContacts = contacts.filter((c) => selectedIds.has(c.id))

  // 選択件数が減ったときにインデックスを範囲内にクランプ
  useEffect(() => {
    if (selectedContacts.length === 0) return
    const clamped = Math.min(previewContactIndex, selectedContacts.length - 1)
    if (clamped !== previewContactIndex) {
      setPreviewContactIndex(clamped)
    }
  }, [selectedContacts.length, previewContactIndex, setPreviewContactIndex])

  const safeIndex = Math.max(0, Math.min(previewContactIndex, selectedContacts.length - 1))
  const currentContact: Contact | null = selectedContacts[safeIndex] ?? null

  const defaultTpl = orientation === 'horizontal' ? DEFAULT_TEMPLATE_HORIZONTAL : DEFAULT_TEMPLATE
  const template: Template = selectedTemplate
    ? { ...selectedTemplate, orientation }
    : { ...defaultTpl, orientation }

  const zoomIn = () => setZoom(Math.min(ZOOM_MAX, Math.round((zoom + ZOOM_STEP) * 100) / 100))
  const zoomOut = () => setZoom(Math.max(ZOOM_MIN, Math.round((zoom - ZOOM_STEP) * 100) / 100))
  const zoomReset = () => setZoom(1)

  // 要素配置変更ハンドラ
  function handleTemplateChange(updated: Template) {
    setSelectedTemplate(updated)
  }

  // ── 背景ドラッグ: 印刷位置補正オフセット ─────────────────────────────────

  const [dragLive, setDragLive] = useState<{ x: number; y: number } | null>(null)
  const dragStart = useRef<{ x: number; y: number; ox: number; oy: number } | null>(null)
  const onMoveRef = useRef<((me: MouseEvent) => void) | null>(null)
  const onUpRef = useRef<((me: MouseEvent) => void) | null>(null)

  // アンマウント時にリスナーを確実に除去
  useEffect(() => {
    return () => {
      if (onMoveRef.current) window.removeEventListener('mousemove', onMoveRef.current)
      if (onUpRef.current) window.removeEventListener('mouseup', onUpRef.current)
      dragStart.current = null
    }
  }, [])

  function handleMouseDown(e: React.MouseEvent) {
    e.preventDefault()
    const start = {
      x: e.clientX,
      y: e.clientY,
      ox: layout.offsetX,
      oy: layout.offsetY,
    }
    dragStart.current = start

    const calcOffset = (me: MouseEvent) => {
      const pxPerMm = zoom * MM_TO_PX
      return {
        x: Math.round((start.ox + (me.clientX - start.x) / pxPerMm) * 10) / 10,
        y: Math.round((start.oy + (me.clientY - start.y) / pxPerMm) * 10) / 10,
      }
    }

    const onMove = (me: MouseEvent) => {
      setDragLive(calcOffset(me))
    }

    const onUp = (me: MouseEvent) => {
      const final = calcOffset(me)
      setLayout({ offsetX: final.x, offsetY: final.y })
      setDragLive(null)
      dragStart.current = null
      window.removeEventListener('mousemove', onMove)
      window.removeEventListener('mouseup', onUp)
      onMoveRef.current = null
      onUpRef.current = null
    }

    onMoveRef.current = onMove
    onUpRef.current = onUp
    window.addEventListener('mousemove', onMove)
    window.addEventListener('mouseup', onUp)
  }

  // ツールバー表示: ドラッグ中はライブ値、それ以外はストアの値
  const displayOffset = dragLive ?? { x: layout.offsetX, y: layout.offsetY }
  const hasOffset = displayOffset.x !== 0 || displayOffset.y !== 0

  return (
    <div className="flex-1 flex flex-col overflow-hidden bg-[#f0f0f0]">
      {/* ツールバー */}
      <div className="flex items-center gap-3 px-4 py-2 bg-white border-b border-gray-200 shrink-0">
        <span className="text-sm font-medium text-gray-700 mr-auto">
          {template.name}
          {selectedContacts.length > 0 && (
            <span className="ml-2 text-xs text-gray-400">
              {safeIndex + 1} / {selectedContacts.length} 件
            </span>
          )}
        </span>
        {/* オフセット表示 */}
        {currentContact && hasOffset && (
          <div className="flex items-center gap-1 text-xs text-amber-600">
            <span>
              補正: X {displayOffset.x.toFixed(1)} / Y {displayOffset.y.toFixed(1)} mm
            </span>
            <button
              onClick={resetOffset}
              className="underline hover:text-amber-800"
              title="補正を初期値に戻す"
            >
              リセット
            </button>
          </div>
        )}
        {/* ズームコントロール */}
        <div className="flex items-center gap-1">
          <button
            onClick={zoomOut}
            disabled={zoom <= ZOOM_MIN}
            className="px-2 py-1 text-sm rounded border border-gray-300 hover:bg-gray-100 disabled:opacity-40"
            aria-label="ズームアウト"
          >
            −
          </button>
          <button
            onClick={zoomReset}
            className="px-3 py-1 text-xs rounded border border-gray-300 hover:bg-gray-100 min-w-[52px] text-center"
          >
            {Math.round(zoom * 100)}%
          </button>
          <button
            onClick={zoomIn}
            disabled={zoom >= ZOOM_MAX}
            className="px-2 py-1 text-sm rounded border border-gray-300 hover:bg-gray-100 disabled:opacity-40"
            aria-label="ズームイン"
          >
            ＋
          </button>
        </div>
      </div>

      {/* キャンバスエリア */}
      <div className="flex-1 overflow-auto flex items-center justify-center p-6">
        {currentContact ? (
          // オフセット補正を CSS transform で可視化。
          // 背景ドラッグ → 印刷位置補正 / カラーハンドルドラッグ → 要素個別配置
          <div
            onMouseDown={handleMouseDown}
            style={{
              position: 'relative',
              display: 'inline-block',
              transform: `translate(${displayOffset.x * zoom * MM_TO_PX}px, ${displayOffset.y * zoom * MM_TO_PX}px)`,
              transition: dragLive ? 'none' : 'transform 0.1s ease',
              cursor: dragLive ? 'grabbing' : 'grab',
            }}
            title="背景ドラッグ: 印刷位置補正 / カラーハンドルドラッグ: 要素の位置調整"
          >
            <LabelStack
              contact={currentContact}
              template={template}
              zoom={zoom}
              watermark={watermark}
              qrConfig={qrConfig}
            />
            {/* 要素配置ハンドル (pointer-events: none のラッパー内で各ハンドルだけ auto) */}
            <div style={{ position: 'absolute', inset: 0, pointerEvents: 'none' }}>
              <LabelEditorOverlay
                template={template}
                zoom={zoom}
                onTemplateChange={handleTemplateChange}
              />
            </div>
          </div>
        ) : (
          <p className="text-gray-400 text-sm">住所録から連絡先を選択してください</p>
        )}
      </div>

      {/* サムネイルナビゲーション (複数選択時) */}
      {selectedContacts.length > 1 && (
        <div className="shrink-0 bg-white border-t border-gray-200 px-4 py-2 flex gap-2 overflow-x-auto">
          {selectedContacts.map((c, i) => (
            <button
              key={c.id}
              onClick={() => setPreviewContactIndex(i)}
              className={`shrink-0 flex flex-col items-center gap-1 p-1 rounded border-2 transition-colors ${
                i === safeIndex
                  ? 'border-blue-500 bg-blue-50'
                  : 'border-transparent hover:border-gray-300'
              }`}
              title={`${c.familyName} ${c.givenName}`}
            >
              <div className="overflow-hidden rounded" style={{ transform: 'scale(1)', transformOrigin: 'top left' }}>
                <LabelStack
                  contact={c}
                  template={template}
                  zoom={0.35}
                  watermark={watermark}
                  qrConfig={qrConfig}
                />
              </div>
              <span className="text-[10px] text-gray-600 max-w-[80px] truncate">
                {c.familyName} {c.givenName}
              </span>
            </button>
          ))}
        </div>
      )}
    </div>
  )
}

/** LabelCanvas + WatermarkLayer + QROverlay の積み重ねコンテナ */
interface LabelStackProps {
  contact: Contact
  template: Template
  zoom: number
  watermark: Watermark | null
  qrConfig: QRConfig
}

function LabelStack({ contact, template, zoom, watermark, qrConfig }: LabelStackProps) {
  return (
    <div className="relative shadow-md" style={{ display: 'inline-block' }}>
      <LabelCanvas contact={contact} template={template} zoom={zoom} />
      <WatermarkLayer
        watermark={watermark}
        labelWidth={template.labelWidth}
        labelHeight={template.labelHeight}
        zoom={zoom}
      />
      <QROverlay
        qrConfig={qrConfig}
        labelWidth={template.labelWidth}
        labelHeight={template.labelHeight}
        zoom={zoom}
      />
    </div>
  )
}

